# backend/app/api/v1/routes.py import logging from fastapi import APIRouter, HTTPException, Request from langchain_core.messages import HumanMessage import httpx
from app.models.schemas import ChatRequest, ChatResponse from app.config import settings
router = APIRouter() logger = logging.getLogger(__name__)
@router.post("/chat", response_model=ChatResponse) async def chat(request: ChatRequest, req: Request) -> ChatResponse: """Send a message to the multi-agent system.""" graph = req.app.state.graph config = {"configurable": {"thread_id": request.session_id}} try: result = await graph.ainvoke( {"messages": [HumanMessage(content=request.message)]}, config=config, ) content = result["messages"][-1].content return ChatResponse(session_id=request.session_id, content=content) except Exception as e: logger.error("Graph failed for session %s: %s", request.session_id, str(e)) raise HTTPException(status_code=500, detail="Agent system error. Check server logs.")
@router.get("/health") async def health_check(): """Check system health and Ollama connectivity.""" async with httpx.AsyncClient(timeout=5.0) as client: try: r = await client.get(settings.ollama_base_url) ollama_ok = r.status_code == 200 except Exception: ollama_ok = False return { "status": "ok" if ollama_ok else "degraded", "ollama": "connected" if ollama_ok else "unreachable", "ollama_url": settings.ollama_base_url, }
